import tarfile
import os

def extract_tar(tar_filepath, destination_dir):
    """
    Extracts a tar file to a specified destination directory.

    Args:
        tar_filepath (str): The path to the tar file to be extracted.
        destination_dir (str): The path to the directory where the contents
                               will be extracted. This directory will be
                               created if it doesn't exist.

    Raises:
        FileNotFoundError: If the tar_filepath does not exist.
        tarfile.ReadError: If the file is not a valid tar file or is corrupted.
        Exception: For other potential errors during extraction.
    """
    if not os.path.exists(tar_filepath):
        raise FileNotFoundError(f"Tar file not found: {tar_filepath}")

    # Ensure the destination directory exists
    os.makedirs(destination_dir, exist_ok=True)

    try:
        with tarfile.open(tar_filepath, 'r') as tar:
            tar.extractall(path=destination_dir)
    except tarfile.ReadError as e:
        raise tarfile.ReadError(f"Error reading tar file '{tar_filepath}': {e}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred during extraction of '{tar_filepath}': {e}")